import java.util.Scanner;

public class SafeBufferHandling {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine(); // Read entire line to handle spaces

        // Creating a buffer with the length of the input
        char[] buffer = new char[name.length()];

        // Copying user input into the buffer with bounds checking
        for (int i = 0; i < name.length(); i++) {
            if (i < buffer.length) {
                buffer[i] = name.charAt(i);
            } else {
                break; // Stop copying if buffer size is reached
            }
        }

        System.out.println("Hello, " + String.valueOf(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
